function upsert_page_by_slug($args) {
    $existing = get_page_by_path($args['post_name'], OBJECT, 'page');
    if ($existing) {
        wp_update_post(array_merge(['ID' => $existing->ID], $args));
        return $existing->ID;
    }
    return wp_insert_post($args);
}
